SELECT measure_type, measure_effectiveness
FROM safety_measures
WHERE measure_effectiveness >= 4;

SELECT injury_type
FROM accident_injuries
WHERE injury_severity = 1;

SELECT accident_id, COUNT(injury_id) AS number_of_injuries
FROM accident_injuries
GROUP BY accident_id;

SELECT DISTINCT accident_type
FROM accidents
ORDER BY accident_type ASC;

SELECT DISTINCT p.name
FROM parties p
JOIN accident_involvements ai ON p.party_id = ai.party_id;
